('business:4-2-quality-of-goods-services:match:4c05a4bd', 'business', 'business:4-2-quality-of-goods-services', '4.2 Quality of Goods & Services', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Quality”?", "options": ["Goods that fail quality inspection but can still be sold to customers at a reduced price, resulting in lower revenue for the business.", "A key principle of quality assurance (associated with Toyota) where all employees constantly look for ways to improve quality and reduce waste.", "A product or service that is fit for purpose, meets legislative rules, and meets customer expectations.", "A method of quality control where customers are asked to rate their experience so a business can identify problems and improvements."]}'::jsonb, '{"answer": 2, "explain": "“Quality” means: A product or service that is fit for purpose, meets legislative rules, and meets customer expectations."}'::jsonb),
('business:4-2-quality-of-goods-services:match:f7116f73', 'business', 'business:4-2-quality-of-goods-services', '4.2 Quality of Goods & Services', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Quality Control”?", "options": ["Resources (materials, labour, time) used to produce goods that turn out to be faulty and cannot be sold at full price.", "A product or service that is fit for purpose, meets legislative rules, and meets customer expectations.", "A system for inspecting the quality of goods or services produced by specialist inspectors to ensure they meet a good standard.", "A key principle of quality assurance (associated with Toyota) where all employees constantly look for ways to improve quality and reduce waste."]}'::jsonb, '{"answer": 2, "explain": "“Quality Control” means: A system for inspecting the quality of goods or services produced by specialist inspectors to ensure they meet a good standard."}'::jsonb),
('business:4-2-quality-of-goods-services:match:f963774f', 'business', 'business:4-2-quality-of-goods-services', '4.2 Quality of Goods & Services', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Quality Assurance”?", "options": ["Goods that fail quality inspection but can still be sold to customers at a reduced price, resulting in lower revenue for the business.", "An approach that involves the whole business focusing on quality, aiming to prevent quality problems from arising at every stage of production.", "An environment in a business where every employee at every level takes personal responsibility for maintaining quality standards.", "A method of quality control where customers are asked to rate their experience so a business can identify problems and improvements."]}'::jsonb, '{"answer": 1, "explain": "“Quality Assurance” means: An approach that involves the whole business focusing on quality, aiming to prevent quality problems from arising at every stage of production."}'::jsonb),
('business:4-2-quality-of-goods-services:match:0239dd17', 'business', 'business:4-2-quality-of-goods-services', '4.2 Quality of Goods & Services', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Returns”?", "options": ["A system for inspecting the quality of goods or services produced by specialist inspectors to ensure they meet a good standard.", "Goods that fail quality inspection but can still be sold to customers at a reduced price, resulting in lower revenue for the business.", "A person who pretends to be a normal customer but secretly evaluates whether the service provided meets the required standard.", "Goods which customers take back to the shop because there are problems with the quality of them."]}'::jsonb, '{"answer": 3, "explain": "“Returns” means: Goods which customers take back to the shop because there are problems with the quality of them."}'::jsonb),
('business:4-2-quality-of-goods-services:match:89cc40df', 'business', 'business:4-2-quality-of-goods-services', '4.2 Quality of Goods & Services', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Recalls”?", "options": ["When a fault occurs with a product and the business asks for the product to be brought back so it can be repaired or replaced.", "Goods which customers take back to the shop because there are problems with the quality of them.", "A product that fulfils its intended function and meets the reasonable expectations of the customer for the price paid.", "An approach that involves the whole business focusing on quality, aiming to prevent quality problems from arising at every stage of production."]}'::jsonb, '{"answer": 0, "explain": "“Recalls” means: When a fault occurs with a product and the business asks for the product to be brought back so it can be repaired or replaced."}'::jsonb),
('business:4-2-quality-of-goods-services:match:7ce5518d', 'business', 'business:4-2-quality-of-goods-services', '4.2 Quality of Goods & Services', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Mystery Shopper”?", "options": ["Goods that fail quality inspection but can still be sold to customers at a reduced price, resulting in lower revenue for the business.", "A key principle of quality assurance (associated with Toyota) where all employees constantly look for ways to improve quality and reduce waste.", "A system for inspecting the quality of goods or services produced by specialist inspectors to ensure they meet a good standard.", "A person who pretends to be a normal customer but secretly evaluates whether the service provided meets the required standard."]}'::jsonb, '{"answer": 3, "explain": "“Mystery Shopper” means: A person who pretends to be a normal customer but secretly evaluates whether the service provided meets the required standard."}'::jsonb),
('business:4-2-quality-of-goods-services:match:d12a8aae', 'business', 'business:4-2-quality-of-goods-services', '4.2 Quality of Goods & Services', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Fit for Purpose”?", "options": ["A person who pretends to be a normal customer but secretly evaluates whether the service provided meets the required standard.", "A product or service that is fit for purpose, meets legislative rules, and meets customer expectations.", "A key principle of quality assurance (associated with Toyota) where all employees constantly look for ways to improve quality and reduce waste.", "A product that fulfils its intended function and meets the reasonable expectations of the customer for the price paid."]}'::jsonb, '{"answer": 3, "explain": "“Fit for Purpose” means: A product that fulfils its intended function and meets the reasonable expectations of the customer for the price paid."}'::jsonb),
('business:4-2-quality-of-goods-services:match:cf26da78', 'business', 'business:4-2-quality-of-goods-services', '4.2 Quality of Goods & Services', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Waste (in quality context)”?", "options": ["When a fault occurs with a product and the business asks for the product to be brought back so it can be repaired or replaced.", "A person who pretends to be a normal customer but secretly evaluates whether the service provided meets the required standard.", "Resources (materials, labour, time) used to produce goods that turn out to be faulty and cannot be sold at full price.", "A system for inspecting the quality of goods or services produced by specialist inspectors to ensure they meet a good standard."]}'::jsonb, '{"answer": 2, "explain": "“Waste (in quality context)” means: Resources (materials, labour, time) used to produce goods that turn out to be faulty and cannot be sold at full price."}'::jsonb),
('business:4-2-quality-of-goods-services:match:ad390920', 'business', 'business:4-2-quality-of-goods-services', '4.2 Quality of Goods & Services', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Customer Satisfaction Survey”?", "options": ["A method of quality control where customers are asked to rate their experience so a business can identify problems and improvements.", "A product that fulfils its intended function and meets the reasonable expectations of the customer for the price paid.", "A system for inspecting the quality of goods or services produced by specialist inspectors to ensure they meet a good standard.", "A person who pretends to be a normal customer but secretly evaluates whether the service provided meets the required standard."]}'::jsonb, '{"answer": 0, "explain": "“Customer Satisfaction Survey” means: A method of quality control where customers are asked to rate their experience so a business can identify problems and improvements."}'::jsonb),
('business:4-2-quality-of-goods-services:match:9d512ee7', 'business', 'business:4-2-quality-of-goods-services', '4.2 Quality of Goods & Services', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Continuous Improvement”?", "options": ["A key principle of quality assurance (associated with Toyota) where all employees constantly look for ways to improve quality and reduce waste.", "Goods that fail quality inspection but can still be sold to customers at a reduced price, resulting in lower revenue for the business.", "A person who pretends to be a normal customer but secretly evaluates whether the service provided meets the required standard.", "A method of quality control where customers are asked to rate their experience so a business can identify problems and improvements."]}'::jsonb, '{"answer": 0, "explain": "“Continuous Improvement” means: A key principle of quality assurance (associated with Toyota) where all employees constantly look for ways to improve quality and reduce waste."}'::jsonb),
('business:4-2-quality-of-goods-services:match:d5fa770e', 'business', 'business:4-2-quality-of-goods-services', '4.2 Quality of Goods & Services', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Culture of Quality”?", "options": ["An environment in a business where every employee at every level takes personal responsibility for maintaining quality standards.", "An approach that involves the whole business focusing on quality, aiming to prevent quality problems from arising at every stage of production.", "When a fault occurs with a product and the business asks for the product to be brought back so it can be repaired or replaced.", "A product that fulfils its intended function and meets the reasonable expectations of the customer for the price paid."]}'::jsonb, '{"answer": 0, "explain": "“Culture of Quality” means: An environment in a business where every employee at every level takes personal responsibility for maintaining quality standards."}'::jsonb),
('business:4-2-quality-of-goods-services:match:e012d666', 'business', 'business:4-2-quality-of-goods-services', '4.2 Quality of Goods & Services', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Seconds”?", "options": ["An environment in a business where every employee at every level takes personal responsibility for maintaining quality standards.", "A person who pretends to be a normal customer but secretly evaluates whether the service provided meets the required standard.", "Goods that fail quality inspection but can still be sold to customers at a reduced price, resulting in lower revenue for the business.", "Resources (materials, labour, time) used to produce goods that turn out to be faulty and cannot be sold at full price."]}'::jsonb, '{"answer": 2, "explain": "“Seconds” means: Goods that fail quality inspection but can still be sold to customers at a reduced price, resulting in lower revenue for the business."}'::jsonb),
('business:4-3-sales-process-customer-service:exam:bc125adf', 'business', 'business:4-3-sales-process-customer-service', '4.3 The Sales Process', 'exam', 'mcq', 1, '{"num": "Q2", "question": "Which of the following is an advantage to the manufacturer of selling face to face to jewellery stores?", "options": ["The cut and colour of the diamonds can be clearly demonstrated", "The jewellery stores have the opportunity to negotiate very low prices", "The risk of the rings being stolen is kept as low as possible", "The sales staff can give out lots of free samples"], "caseStudy": "A manufacturer of diamond rings employs sales staff to visit jewellery stores across the UK to encourage them to purchase its products.", "hint": "Think about what face-to-face selling uniquely allows that e-commerce or telesales cannot — particularly for a high-value, visual product like diamond rings.", "starter": "The correct answer is A because..."}'::jsonb, '{"answer": 0, "markScheme": "<div class=\"marks-section\"><h5>Answer: A</h5>\n<p><strong>A — The cut and colour of the diamonds can be clearly demonstrated.</strong></p>\n<p><strong>Why A is correct:</strong> Face-to-face selling allows the physical product to be examined in person. For diamond rings, where cut, colour, clarity, and craftsmanship are key selling points, a live demonstration is far more effective than an image or telephone description.</p>\n<p><strong>Why the others are wrong:</strong></p>\n<ul>\n<li><strong>B — Negotiating very low prices</strong> is a benefit to the BUYER (jewellery stores), not the manufacturer/seller.</li>\n<li><strong>C — Reducing theft risk</strong> is not a specific or notable advantage of face-to-face selling over other methods.</li>\n<li><strong>D — Free samples</strong> are not realistic for diamond rings, and giving away samples is not a defining feature of face-to-face selling.</li>\n</ul></div>", "modelAnswer": ""}'::jsonb),
('business:4-3-sales-process-customer-service:exam:b76b0eac', 'business', 'business:4-3-sales-process-customer-service', '4.3 The Sales Process', 'exam', 'mcq', 1, '{"num": "Q6", "question": "Customer engagement:", "options": ["Allows customers to try before they buy", "Contributes to good customer service", "Improves the product knowledge of employees", "Shortens the supply chain"], "hint": "Think about the official definition of customer engagement — what does it directly contribute to in a business?", "starter": "The correct answer is B because..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\"><h5>Answer: B</h5>\n<p><strong>B — Contributes to good customer service.</strong></p>\n<p><strong>Why B is correct:</strong> Customer engagement (the contact between business and customer) is one of the key ways a business delivers good customer service — well-trained, engaged staff build loyalty and improve customer satisfaction.</p>\n<p><strong>Why the others are wrong:</strong></p>\n<ul>\n<li><strong>A — Trying before buying</strong> is a feature of face-to-face retail, not customer engagement per se.</li>\n<li><strong>C — Improving product knowledge of employees</strong> is about staff training, not customer engagement.</li>\n<li><strong>D — Shortening the supply chain</strong> is a logistics and procurement concept, unrelated to customer engagement.</li>\n</ul>\n<p><strong>Examiner''s Comment:</strong> Some students showed misunderstanding of ''customer engagement''. Always take time to read what the question is actually asking.</p></div>", "modelAnswer": ""}'::jsonb),
('business:4-3-sales-process-customer-service:exam:cd3a5e94', 'business', 'business:4-3-sales-process-customer-service', '4.3 The Sales Process', 'exam', 'mcq', 1, '{"num": "Q8", "question": "Which of the following would help Geoff deal with this problem?", "options": ["Advertise other second-hand book shops in the area", "Close the shop early on weekdays in the school holidays", "Improve customer service by being friendly and polite", "Offer a free book to new customers who spend over £5"], "caseStudy": "Geoff, a sole trader, owns a second-hand book shop. Despite being well advertised and selling reasonably priced products, the shop has difficulty retaining customers.", "hint": "Geoff can gain customers (advertising is working and prices are good) but cannot KEEP them. Which option directly addresses the post-purchase experience and encourages customers to return?", "starter": "The correct answer is C because..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\"><h5>Answer: C</h5>\n<p><strong>C — Improve customer service by being friendly and polite.</strong></p>\n<p><strong>Why C is correct:</strong> The shop is advertised and prices are reasonable — marketing and pricing are not the issue. The problem is RETENTION. Friendly, polite customer service improves the experience and gives customers a reason to return.</p>\n<p><strong>Why the others are wrong:</strong></p>\n<ul>\n<li><strong>A — Advertising other book shops</strong> would actively help competitors and drive customers away from Geoff''s shop.</li>\n<li><strong>B — Closing early</strong> reduces accessibility and would make retention worse, not better.</li>\n<li><strong>D — Free book for new customers</strong> targets gaining NEW customers, but the problem stated is retaining EXISTING ones.</li>\n</ul></div>", "modelAnswer": ""}'::jsonb),
('business:4-3-sales-process-customer-service:exam:88ea4383', 'business', 'business:4-3-sales-process-customer-service', '4.3 The Sales Process', 'exam', 'mcq', 1, '{"num": "Q9", "question": "This is an example of:", "options": ["After-sales service", "E-commerce", "Face to face selling", "Telesales"], "caseStudy": "An assistant serves a customer who has come into the post office to top-up their mobile phone credit.", "hint": "The customer physically enters a building and is served in person. Which method of selling involves direct contact between buyer and seller in a physical location?", "starter": "The correct answer is C because..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\"><h5>Answer: C</h5>\n<p><strong>C — Face to face selling.</strong></p>\n<p><strong>Why C is correct:</strong> The customer visits a physical location (post office) and is served directly by an assistant — direct contact between buyer and seller defines face-to-face selling.</p>\n<p><strong>Why the others are wrong:</strong></p>\n<ul>\n<li><strong>A — After-sales service</strong> is advice or help AFTER a purchase has already been made, not at the point of sale.</li>\n<li><strong>B — E-commerce</strong> involves buying and selling electronically — there is no online element here.</li>\n<li><strong>D — Telesales</strong> is completed over the telephone — the customer is physically present, not calling.</li>\n</ul></div>", "modelAnswer": ""}'::jsonb),
('business:4-3-sales-process-customer-service:exam:8467913c', 'business', 'business:4-3-sales-process-customer-service', '4.3 The Sales Process', 'exam', 'mcq', 1, '{"num": "Q11", "question": "Which aspect of the business is most likely to need improving?", "options": ["After-sales service", "E-commerce", "Marketing", "Procurement"], "caseStudy": "A business finds it relatively easy to gain customers but has great difficulty retaining these customers.", "hint": "The business gains customers easily — so what is already working? The problem is keeping customers AFTER their first purchase. Which aspect deals with the post-purchase experience?", "starter": "The correct answer is A because..."}'::jsonb, '{"answer": 0, "markScheme": "<div class=\"marks-section\"><h5>Answer: A</h5>\n<p><strong>A — After-sales service.</strong></p>\n<p><strong>Why A is correct:</strong> Marketing (C) is clearly working — the business gains customers easily. The problem is RETENTION. After-sales service determines how customers are treated after a purchase — poor after-sales service leads to customers not returning.</p>\n<p><strong>Why the others are wrong:</strong></p>\n<ul>\n<li><strong>B — E-commerce</strong> relates to the selling method, not to why customers stop returning.</li>\n<li><strong>C — Marketing</strong> is what gains customers — the question confirms this is already working well.</li>\n<li><strong>D — Procurement</strong> relates to buying supplies and inputs, not customer retention.</li>\n</ul></div>", "modelAnswer": ""}'::jsonb),
('business:4-3-sales-process-customer-service:exam:8d7b6d8f', 'business', 'business:4-3-sales-process-customer-service', '4.3 The Sales Process', 'exam', 'mcq', 1, '{"num": "Q13", "question": "Which one of the following will NOT improve the level of customer service the store offers?", "options": ["Demonstrating to all staff how to be attentive, polite and helpful", "Giving the sales assistants lists detailing the features of each phone", "Offering a free phone case with every mobile phone purchased", "Training the store manager to deal with technical queries"], "caseStudy": "A store that sells mobile phones wishes to improve the level of customer service it offers to those who come into the store.", "hint": "Think about what customer service actually means — the quality of interaction, advice, and assistance provided. Which option is a promotional or pricing decision rather than a customer service improvement?", "starter": "The correct answer is C because..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\"><h5>Answer: C</h5>\n<p><strong>C — Offering a free phone case with every mobile phone purchased.</strong></p>\n<p><strong>Why C is correct:</strong> A free phone case is a sales promotion / pricing incentive. It may attract customers, but it does not improve the QUALITY of service, advice, or interaction customers receive in store.</p>\n<p><strong>Why the others are wrong (they DO improve customer service):</strong></p>\n<ul>\n<li><strong>A</strong> — Training staff to be attentive and polite directly improves customer engagement — a key part of customer service.</li>\n<li><strong>B</strong> — Giving staff product feature lists improves product knowledge, enabling better advice for customers.</li>\n<li><strong>D</strong> — Training the manager to handle technical queries improves after-sales service and the ability to resolve customer problems effectively.</li>\n</ul></div>", "modelAnswer": ""}'::jsonb),
('business:4-3-sales-process-customer-service:exam:4c1aa491', 'business', 'business:4-3-sales-process-customer-service', '4.3 The Sales Process', 'exam', 'mcq', 1, '{"num": "Q16", "question": "What is e-commerce?", "options": ["A method used to ensure quality", "A planning tool", "A type of bank loan", "A way to sell goods on the Internet"], "hint": "Think about the official definition — e-commerce involves buying and selling using internet technology.", "starter": "The correct answer is D because..."}'::jsonb, '{"answer": 3, "markScheme": "<div class=\"marks-section\"><h5>Answer: D</h5>\n<p><strong>D — A way to sell goods on the Internet.</strong></p>\n<p><strong>Why D is correct:</strong> E-commerce is the bringing together of buying and selling electronically — commonly known as online sales via the internet.</p>\n<p><strong>Why the others are wrong:</strong></p>\n<ul>\n<li><strong>A</strong> — Quality control and quality assurance are methods to ensure quality, not e-commerce.</li>\n<li><strong>B</strong> — Planning tools include cash flow forecasts and SWOT analysis, not e-commerce.</li>\n<li><strong>C</strong> — A bank loan is a source of finance, completely unrelated to e-commerce.</li>\n</ul></div>", "modelAnswer": ""}'::jsonb),
('business:4-3-sales-process-customer-service:exam:c6d615df', 'business', 'business:4-3-sales-process-customer-service', '4.3 The Sales Process', 'exam', 'mcq', 1, '{"num": "Q17", "question": "Which one of the following businesses is most likely to use telesales?", "options": ["A burger van", "A petrol station", "A school", "An insurance company"], "hint": "Think about which type of business primarily sells its products or services by phone — where customers call to get a quote, renew a policy, or make a purchase without needing to see anything in person.", "starter": "The correct answer is D because..."}'::jsonb, '{"answer": 3, "markScheme": "<div class=\"marks-section\"><h5>Answer: D</h5>\n<p><strong>D — An insurance company.</strong></p>\n<p><strong>Why D is correct:</strong> Insurance companies are classic users of telesales — customers call to get quotes, compare options, negotiate premiums, and renew policies over the phone. The product (insurance) is intangible and requires no physical demonstration, making telephone sales ideal.</p>\n<p><strong>Why the others are wrong:</strong></p>\n<ul>\n<li><strong>A</strong> — A burger van sells face-to-face at a physical location to passing customers.</li>\n<li><strong>B</strong> — A petrol station sells face-to-face at a physical location.</li>\n<li><strong>C</strong> — A school provides education services rather than selling products through telesales.</li>\n</ul></div>", "modelAnswer": ""}'::jsonb),
('business:4-3-sales-process-customer-service:exam:137940c2', 'business', 'business:4-3-sales-process-customer-service', '4.3 The Sales Process', 'exam', 'mcq', 1, '{"num": "Q19", "question": "Which of the following is this an example of?", "options": ["Face to face selling", "International branding", "Sales promotion", "Telesales"], "caseStudy": "A customer comes into a travel agency to book a holiday to Australia. An assistant serves the customer.", "hint": "The customer physically visits a location and is served in person. Which method of selling is defined by direct physical contact between buyer and seller?", "starter": "The correct answer is A because..."}'::jsonb, '{"answer": 0, "markScheme": "<div class=\"marks-section\"><h5>Answer: A</h5>\n<p><strong>A — Face to face selling.</strong></p>\n<p><strong>Why A is correct:</strong> The customer physically enters the travel agency and is served directly by an assistant — direct contact between buyer and seller in a physical setting is the definition of face-to-face selling.</p>\n<p><strong>Why the others are wrong:</strong></p>\n<ul>\n<li><strong>B — International branding</strong> refers to developing a brand identity across countries, not a method of selling.</li>\n<li><strong>C — Sales promotion</strong> refers to short-term marketing incentives (discounts, offers), not the method of selling.</li>\n<li><strong>D — Telesales</strong> would require the customer to be on the phone, not physically present.</li>\n</ul></div>", "modelAnswer": ""}'::jsonb),
('business:4-3-sales-process-customer-service:exam:9b8efc96', 'business', 'business:4-3-sales-process-customer-service', '4.3 The Sales Process', 'exam', 'mcq', 1, '{"num": "Q20", "question": "Which of the following will NOT improve customer engagement?", "options": ["Training staff on the benefit of coconuts", "Only selling products that have been certified as organic", "Sending carefully worded personalised emails to interested customers", "Sending text messages to all previous customers about the benefits of coconut oil"], "caseStudy": "Coconut Life uses e-commerce to sell its range of innovative coconut products.", "hint": "Customer engagement is about improving the CONTACT between the business and its customers. Which option is a product sourcing or quality decision rather than a communication or interaction improvement?", "starter": "The correct answer is B because..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\"><h5>Answer: B</h5>\n<p><strong>B — Only selling products that have been certified as organic.</strong></p>\n<p><strong>Why B is correct:</strong> This is a product sourcing or quality decision — it may influence what is sold, but it does NOT directly improve the CONTACT or interaction between Coconut Life and its customers. Customer engagement requires active communication and connection.</p>\n<p><strong>Why the others are wrong (they DO improve engagement):</strong></p>\n<ul>\n<li><strong>A</strong> — Training staff improves their ability to advise and connect with customers when interacting with them.</li>\n<li><strong>C</strong> — Personalised emails are a direct, thoughtful form of customer contact and engagement.</li>\n<li><strong>D</strong> — Text messages to previous customers are a form of ongoing contact and engagement.</li>\n</ul>\n<p><strong>Examiner''s Comment:</strong> Some students misunderstood ''customer engagement''. Also note this question asks what will NOT improve it — always check whether you are looking for the item that will or will not do something.</p></div>", "modelAnswer": ""}'::jsonb),
('business:4-3-sales-process-customer-service:exam:c1a940fe', 'business', 'business:4-3-sales-process-customer-service', '4.3 The Sales Process', 'exam', 'mcq', 1, '{"num": "JCM Q1", "question": "Face-to-face selling involves:", "options": ["Advertising goods on a website", "A buyer meeting with a seller", "A seller telephoning buyers to ask them if they want to buy", "Using a website to take orders from customers"], "caseStudy": "JC Motors Ltd have been trading for 10 years. They specialise in selling high-end bespoke cars that start from £50,000 and can be as expensive as £300,000. They are renowned for their excellent customer service as they are always willing to go the extra mile to make customers feel special. Customers are offered a wide range of hot drinks and snacks on arrival that is served to them in the luxurious seating area. Children can be kept entertained with miniature electric cars that they can drive around the specially designed track. The staff have excellent knowledge about each car and are always available following the purchase of the car to answer any queries. JC Motors Ltd have also sold several cars to customers worldwide owing to their website that offers to ship their cars around the globe.", "hint": "What is the one defining feature of face-to-face selling that makes it different from all other methods?", "starter": "The correct answer is B because..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\"><h5>Answer: B</h5>\n<p><strong>B — A buyer meeting with a seller.</strong></p>\n<p><strong>Why B is correct:</strong> Face-to-face selling requires direct physical contact between buyer and seller — they meet in person. This is what makes it distinctly different from all other selling methods.</p>\n<p><strong>Why the others are wrong:</strong></p>\n<ul>\n<li><strong>A — Advertising on a website</strong> is digital marketing, not a selling method involving personal contact.</li>\n<li><strong>C — Telephoning buyers</strong> describes telesales, not face-to-face selling.</li>\n<li><strong>D — Using a website to take orders</strong> describes e-commerce.</li>\n</ul></div>", "modelAnswer": ""}'::jsonb),
('business:4-3-sales-process-customer-service:mcq:102c3de8', 'business', 'business:4-3-sales-process-customer-service', '4.3 The Sales Process', 'mcq', 'mcq', 1, '{"question": "Which of the following is the correct definition of e-commerce?", "options": ["The buying and selling of goods in a physical shop", "The bringing together of buying and selling electronically", "Selling goods over the telephone", "The delivery of goods using drones"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: E-commerce is specifically defined as the bringing together of buying and selling electronically (online sales). It always involves some form of physical delivery after the online sale — unlike digital distribution where the product itself is delivered digitally."}'::jsonb),
('business:4-3-sales-process-customer-service:mcq:163695bc', 'business', 'business:4-3-sales-process-customer-service', '4.3 The Sales Process', 'mcq', 'mcq', 1, '{"question": "Which of the following is an advantage to a BUSINESS of using e-commerce?", "options": ["Customers can compare prices easily across multiple websites", "Customers can shop at any time of day or night", "Lower operating costs as no expensive shop premises are needed", "Customers can touch and examine products before buying"]}'::jsonb, '{"answer": 2, "explain": "Correct answer: Lower operating costs is an advantage to the BUSINESS — no need to pay expensive city-centre rents. Options A, B, and D are advantages to CUSTOMERS, not businesses. Always check whose perspective the question is asking about."}'::jsonb),
('business:4-3-sales-process-customer-service:mcq:aed68eb6', 'business', 'business:4-3-sales-process-customer-service', '4.3 The Sales Process', 'mcq', 'mcq', 1, '{"question": "Customer engagement refers to:", "options": ["Allowing customers to try products before they buy", "The contact between the business and customer", "Improving the product knowledge of employees", "Shortening the supply chain"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: Customer engagement is defined as the contact between the business and customer. This includes face-to-face interaction in stores, friendly voices in telesales, and carefully worded emails/texts in e-commerce."}'::jsonb),
('business:4-3-sales-process-customer-service:mcq:7097e35e', 'business', 'business:4-3-sales-process-customer-service', '4.3 The Sales Process', 'mcq', 'mcq', 1, '{"question": "A business finds it easy to gain customers but has difficulty retaining them. Which aspect of the business most likely needs improving?", "options": ["After-sales service", "E-commerce", "Marketing", "Procurement"]}'::jsonb, '{"answer": 0, "explain": "Correct answer: After-sales service. Marketing (C) is clearly working — it is attracting customers. The problem is what happens AFTER the sale. After-sales service keeps customers satisfied and coming back."}'::jsonb),
('business:4-3-sales-process-customer-service:mcq:d979aab1', 'business', 'business:4-3-sales-process-customer-service', '4.3 The Sales Process', 'mcq', 'mcq', 1, '{"question": "Face to face selling will help a business most when:", "options": ["The goods being sold are cheap and simple", "Service and advice are important to the customer", "The customer has a computer and internet access", "The goods are small and easily transported"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: Face to face selling is most valuable when service matters — for example, buying a wedding dress, complex electronics, or financial products. The physical presence of staff allows advice, demonstrations, and relationship-building that e-commerce cannot fully replicate."}'::jsonb),
('business:4-3-sales-process-customer-service:mcq:9f6546a6', 'business', 'business:4-3-sales-process-customer-service', '4.3 The Sales Process', 'mcq', 'mcq', 1, '{"question": "Which of the following is a disadvantage to CUSTOMERS of using e-commerce?", "options": ["Having to pay expensive city-centre rents", "Increased worldwide competition from other businesses", "Difficulty keeping up with advances in technology costs", "Inability to touch or inspect products before purchasing"]}'::jsonb, '{"answer": 3, "explain": "Correct answer: Only being able to see images of goods (not touch or inspect them) is a disadvantage to the CUSTOMER. Options A (rents), B (competition), and C (technology update costs) are all disadvantages to BUSINESSES using e-commerce."}'::jsonb),
('business:4-3-sales-process-customer-service:mcq:76661270', 'business', 'business:4-3-sales-process-customer-service', '4.3 The Sales Process', 'mcq', 'mcq', 1, '{"question": "Why is good product knowledge important to a business?", "options": ["It helps recruit better staff to the business", "It will help a business in the sales process", "It will develop better working conditions for staff", "It will mean that training costs are lower"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: Good product knowledge helps staff in the sales process by allowing them to advise customers confidently, increasing the chance of a purchase. It does NOT reduce training costs (D) — in fact, gaining product knowledge requires investment in training."}'::jsonb),
('business:4-3-sales-process-customer-service:mcq:ca827ea1', 'business', 'business:4-3-sales-process-customer-service', '4.3 The Sales Process', 'mcq', 'mcq', 1, '{"question": "Click and collect is best described as:", "options": ["Buying goods in a shop and having them delivered to your home", "Ordering goods online and collecting them from a store at a later time", "Using a phone to order goods from a telesales department", "Returning faulty goods to a warehouse after an online purchase"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: Click and collect means ordering online and collecting goods from a store later. It solves the problem of customers not being home for delivery, while ensuring the product is in stock before the customer makes the journey."}'::jsonb),
('business:4-3-sales-process-customer-service:mcq:5945327a', 'business', 'business:4-3-sales-process-customer-service', '4.3 The Sales Process', 'mcq', 'mcq', 1, '{"question": "Which of the following businesses is most likely to use telesales as a primary method of selling?", "options": ["A burger van", "A petrol station", "A school", "An insurance company"]}'::jsonb, '{"answer": 3, "explain": "Correct answer: An insurance company commonly uses telesales — customers call to get quotes, renew policies, or negotiate better deals. Burger vans (A) and petrol stations (B) use face-to-face selling, and schools (C) do not sell products in the conventional sense."}'::jsonb),
('business:4-3-sales-process-customer-service:mcq:f2bb1ff4', 'business', 'business:4-3-sales-process-customer-service', '4.3 The Sales Process', 'mcq', 'mcq', 1, '{"question": "A manufacturer of diamond rings employs staff to visit jewellery stores. Which is an advantage to the manufacturer of selling face to face?", "options": ["The cut and colour of the diamonds can be clearly demonstrated", "The jewellery stores have the opportunity to negotiate very low prices", "The risk of the rings being stolen is kept as low as possible", "The sales staff can give out lots of free samples"]}'::jsonb, '{"answer": 0, "explain": "Correct answer: Face-to-face selling allows the physical product to be demonstrated and examined — crucial for diamond rings where cut, colour, and quality must be seen in person. Option B (negotiating low prices) is a benefit to the BUYER, not the manufacturer."}'::jsonb),
('business:4-3-sales-process-customer-service:mcq:a0a4ee55', 'business', 'business:4-3-sales-process-customer-service', '4.3 The Sales Process', 'mcq', 'mcq', 1, '{"question": "Which of the following will NOT improve customer engagement for an e-commerce business?", "options": ["Training staff on the benefits of the product range", "Only selling products that have been certified as organic", "Sending carefully worded personalised emails to interested customers", "Sending text messages to previous customers about new products"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: Only selling certified organic products is a product/sourcing decision — it does not directly improve the CONTACT between the business and customer. Options A, C, and D all directly improve how the business communicates and connects with its customers."}'::jsonb),
('business:4-3-sales-process-customer-service:mcq:2da87c1d', 'business', 'business:4-3-sales-process-customer-service', '4.3 The Sales Process', 'mcq', 'mcq', 1, '{"question": "Which of the following would help a sole trader whose shop has difficulty RETAINING customers?", "options": ["Advertise other competing shops in the local area", "Close the shop early on weekdays in the school holidays", "Improve customer service by being friendly and polite", "Offer a free item to new customers who spend over a threshold"]}'::jsonb, '{"answer": 2, "explain": "Correct answer: If the shop is advertised and prices are reasonable, the problem is RETENTION. Customer service (being friendly and polite) improves customer engagement and gives customers a reason to return. Option D attracts NEW customers, not retains existing ones."}'::jsonb),
('business:4-3-sales-process-customer-service:tf:aae3992f', 'business', 'business:4-3-sales-process-customer-service', '4.3 The Sales Process', 'tf', 'tf', 1, '{"question": "E-commerce involves some form of physical delivery after an online sale."}'::jsonb, '{"answer": true, "explain": "TRUE. This is what distinguishes e-commerce from digital distribution — with e-commerce, the product is still physically delivered to the customer after being purchased online."}'::jsonb),
('business:4-3-sales-process-customer-service:tf:61b2b741', 'business', 'business:4-3-sales-process-customer-service', '4.3 The Sales Process', 'tf', 'tf', 1, '{"question": "A business using e-commerce must always be located near a city centre."}'::jsonb, '{"answer": false, "explain": "FALSE. E-commerce businesses can locate almost anywhere. The ''front end'' (order taking) only requires an internet connection, and the warehouse simply needs to be near good transport links like a motorway network for efficient delivery."}'::jsonb),
('business:4-3-sales-process-customer-service:tf:9751e68f', 'business', 'business:4-3-sales-process-customer-service', '4.3 The Sales Process', 'tf', 'tf', 1, '{"question": "After-sales service is only important if a product is legally required to come with a guarantee."}'::jsonb, '{"answer": false, "explain": "FALSE. After-sales service is important regardless of legal requirements. Businesses that offer refunds or resolve problems (even when not legally required to) build customer loyalty and encourage repeat purchases."}'::jsonb),
('business:4-3-sales-process-customer-service:tf:d9b2e8b9', 'business', 'business:4-3-sales-process-customer-service', '4.3 The Sales Process', 'tf', 'tf', 1, '{"question": "Telesales can be a useful method of selling to older customers who are less comfortable with online shopping."}'::jsonb, '{"answer": true, "explain": "TRUE. Telesales bridges the gap between e-commerce and face-to-face selling. Customers who are not comfortable using the internet may be very happy to talk to someone on the phone and be guided through the buying process."}'::jsonb)
